     Console.WriteLine($"Test set too small ({testCount} rows) for meaningful evaluation. Add more data.");
 }

 // Save the full pipeline (mapping + training) for the prediction engine
 var fullPipeline = mappingPipeline
     .Append(mlContext.Transforms.Categorical.OneHotEncoding("RegionEncoded", nameof(RawCustomerData.Region)))
     .Append(mlContext.Transforms.Concatenate("Features",
         nameof(RawCustomerData.Age),
         nameof(RawCustomerData.Income),
         nameof(RawCustomerData.PurchaseHistory),
         "RegionEncoded"))
     .Append(mlContext.Transforms.NormalizeMinMax("Features"))
     .Append(mlContext.BinaryClassification.Trainers.SdcaLogisticRegression(
         labelColumnName: "Label", featureColumnName: "Features"));

 var fullModel = fullPipeline.Fit(rawData);

 // Save model and register pooled prediction engine
 var modelPath = Path.Combine(AppContext.BaseDirectory, "churn-model.zip");
 mlContext.Model.Save(fullModel, rawData.Schema, modelPath);

 builder.Services.AddPredictionEnginePool<RawCustomerData, ChurnPrediction>()
     .FromFile(modelPath);

 var app = builder.Build();

 app.MapPost("/predict", (PredictionEnginePool<RawCustomerData, ChurnPrediction> pool, CustomerInput input) =>
 {
     var data = new RawCustomerData
     {
         Age = input.Age,
         Income = input.Income,
         Region = input.Region,
         PurchaseHistory = input.PurchaseHistory,
         Churned = ""
     };
     var prediction = pool.Predict(data);
     return Results.Ok(new
     {
         WillChurn = prediction.PredictedLabel,
         Probability = prediction.Probability
     });
 });

 app.Run();

 public class RawCustomerData
 {
     [LoadColumn(0)]
     public float Age { get; set; }

     [LoadColumn(1)]
     public float Income { get; set; }

     [LoadColumn(2)]
     public string Region { get; set; } = string.Empty;

     [LoadColumn(3)]
     public float PurchaseHistory { get; set; }

     [LoadColumn(4)]
     public string Churned { get; set; } = string.Empty;
 }

 public class CustomerInput
 {
     public float Age { get; set; }
     public float Income { get; set; }
     public string Region { get; set; } = string.Empty;
     public float PurchaseHistory { get; set; }
 }

 public class ChurnPrediction
 {
     [ColumnName("PredictedLabel")]
     public bool PredictedLabel { get; set; }

     public float Probability { get; set; }

     public float Score { get; set; }
 }
